   /* === UNIVERSAL ATF (all templates) === */
   {{ body_and_utils_css }}

   {%- if template contains 'index' or template contains 'collection' -%}
   /* === Swiper carousel === */
   {{ swiper_css }}
   {%- endif -%}

   {%- if template contains 'index' -%}
