   {{ accordion_tabs_css }}
   {%- endif -%}

   {%- if template contains 'product' -%}
   /* === Product page === */
   {{ product_page_css }}
   {%- endif -%}

   {%- if template contains 'collection' -%}
   /* === Collection filters + sidebar === */
   {{ collection_filters_css }}
   {%- endif -%}

   {%- if template == 'search' -%}
