## Implementation: document.createElement guard

Place the following inline `<script>` block in layout/theme.liquid IMMEDIATELY before line 683 ({{ content_for_header }}):

```liquid
{%- comment -%}
  VQB performance gate (bd hairmnl-theme-XXXX):
  VisualQuizBuilder loads 447KB on every page via SATCB dynamic injection.
  Only needed on /apps/quiz routes. Block on everything else.
  Guard runs before content_for_header so document.createElement is
  overridden before SATCB fires (SATCB executes post-DOM-parse via async scripts).
{%- endcomment -%}
<script>
(function() {
  var VQB_ORIGINS = ['cdn.visualquizbuilder.com'];
  var QUIZ_PATHS = ['/apps/quiz'];
  var path = window.location.pathname;
  var allowed = QUIZ_PATHS.some(function(p) { return path === p || path.indexOf(p + '/') === 0; });
  if (allowed) return; // quiz page — let VQB load normally

  var _createElement = document.createElement.bind(document);
  document.createElement = function(tag) {
    var el = _createElement.apply(document, arguments);
    if (typeof tag === 'string' && tag.toLowerCase() === 'script') {
      var _setSrc = Object.getOwnPropertyDescriptor(HTMLScriptElement.prototype, 'src').set;
      var blocked = false;
      Object.defineProperty(el, 'src', {
        configurable: true,
        get: function() {
          return Object.getOwnPropertyDescriptor(HTMLScriptElement.prototype, 'src').get.call(this);
        },
        set: function(v) {
          if (!blocked && VQB_ORIGINS.some(function(o) { return String(v).indexOf(o) !== -1; })) {
            blocked = true;
            return; // swallow the src assignment — script never fetches
          }
          _setSrc.call(this, v);
        }
      });
    }
    return el;
  };

  // MutationObserver fallback: catch any <script src="...vqb..."> added via innerHTML
  var observer = new MutationObserver(function(mutations) {
    mutations.forEach(function(m) {
      m.addedNodes.forEach(function(node) {
        if (node.tagName === 'SCRIPT' && node.src &&
            VQB_ORIGINS.some(function(o) { return node.src.indexOf(o) !== -1; })) {
          node.parentNode && node.parentNode.removeChild(node);
        }
      });
    });
  });
  observer.observe(document.documentElement, { childList: true, subtree: true });
})();
</script>
```

